import { Box, Typography } from '@mui/material'
import WhoProfile from '../../../assets/Images/WhoWeAreProfile.jpg'
 
function WhoWeAre() {
  return (
    <Box
    sx={{
        width:"100%",
        height:"90vh",
    }}
    >
     <Typography mt={4} fontSize={42}>Quiénes somos?</Typography>
     <div style={{
        width:"300px",
        height:"300px",
        border:"1px solid",
        margin:"0 auto",
        borderRadius:"100%"
    }}>
        <img src={WhoProfile} style={{
            width:"100%",
            height:"100%",
            objectFit:"contain"
        }}/>
    </div>
    </Box>
  )
}

export default WhoWeAre
